`,o.jsx(r.p,{children:"I made this game with a few of my classmates in my Game Design course. It was the first game I've worked on with a bunch of other people. It was super cool being able to delegate tasks and watch as our separate components eventually came together to form an actual game!"}),`
`,o.jsxs(r.p,{children:["The project came out decently for the time frame we had. Obviously it could have been much more polished if we weren't limited on that front. The guns/enemies are super unbalanced and I think the artwork could use some fine tuning as well, but the core concept is pretty sound. The screen shake is a bit much, but we had discovered how easy it was to apply screen effects in ",o.jsx(r.a,{href:"https://unity.com/",children:"Unity"})," so... why not."]})]})}function X0(i={}){const{wrapper:r}={...Ae(),...i.components};return r?o.jsx(r,{...i,children:o.jsx(Zh,{...i})}):Zh(i)}const Z0=""+new URL("gc1-Fz4XHaGs.png",import.meta.url).href;function Vh(i){const r={em:"em",p:"p",...Ae(),...i.components};return o.jsxs(o.Fragment,{children:[o.jsx(dt,{title:"Game Changer",links:[{text:"Repository",href:"https://github.com/charlesHetterich/Game-Changer"}],color:"#ff6463"}),`
