`,o.jsx(Be,{src:Z0}),`
`,o.jsx(r.p,{children:"I built this originally to get a scholarship to go to Apple's WWDC event. Now when I have friends who have an interest in coding, if they have a mac, this is a quick and easy way for me to help them get started."})]})}function V0(i={}){const{wrapper:r}={...Ae(),...i.components};return r?o.jsx(r,{...i,children:o.jsx(Vh,{...i})}):Vh(i)}function Fh(i){const r={a:"a",em:"em",p:"p",strong:"strong",...Ae(),...i.components};return o.jsxs(o.Fragment,{children:[o.jsx(dt,{title:"Dell Medical   — Psychedelic Research",links:[{text:"Website",href:"https://dellmed.utexas.edu/units/center-for-psychedelic-research-and-therapy"}],color:"#ff6463"}),`
`,o.jsxs(r.p,{children:["In early 2022, I connected with ",o.jsx(r.a,{href:"https://dellmed.utexas.edu/directory/gregory-greg-fonzo",children:"Dr. Greg Fonzo"})," shortly after hearing about the recent opening of UT's ",o.jsx(r.em,{children:"Center for Psychedelic Research & Therapy"}),". ",o.jsx(r.strong,{children:"Psychedelic assisted therapy"})," is something I believe in and I wanted to find out how I could help."]}),`
